const items = $input.all();
return items.map(item => {
  const j = item.json || {};
  const media = j.media || {};
  const messageType = (j.messageType || 'unknown').toString();
  const text = (j.text || '').toString();
  const filename = (media.filename || '').toString();
  const caption = (media.caption || '').toString();
  return {
    json: {
      phone: (j.phone || '').toString(),
      msgId: (j.msgId || '').toString(),
      messageType,
      text,
      media: {
        url: media.url || null,
        base64: media.base64 || null,
        mime_type: media.mime_type || null,
        caption,
        filename
      },
      test_run_id: j.test_run_id || null,
      _skip_llm_calls: j._skip_llm_calls === true
    }
  };
});

const j = $json;
const flags = {
  clinical: false,
  sensitive_image: false,
  payment_proof: false,
  financial: false,
  unknown_media: false,
  audio_transcribed: false,
  image_classified: false
};
return {
  json: {
    phone: j.phone,
    msgId: j.msgId,
    messageType: j.messageType,
    normalized_text: j.text || '',
    media_summary: '',
    safety_flags: flags,
    should_handoff: false,
    handoff_reason: null,
    test_run_id: j.test_run_id
  }
};

const j = $json;
const flags = {
  clinical: false,
  sensitive_image: false,
  payment_proof: false,
  financial: false,
  unknown_media: false,
  audio_transcribed: true,
  image_classified: false
};
const normalized_text = j._skip_llm_calls
  ? '[transcricao simulada]'
  : '[transcricao pendente v2]';
return {
  json: {
    phone: j.phone,
    msgId: j.msgId,
    messageType: j.messageType,
    normalized_text,
    media_summary: 'audio',
    safety_flags: flags,
    should_handoff: false,
    handoff_reason: null,
    test_run_id: j.test_run_id
  }
};

const j = $json;
const caption = (j.media && j.media.caption) || '';
const flags = {
  clinical: false,
  sensitive_image: false,
  payment_proof: false,
  financial: false,
  unknown_media: false,
  audio_transcribed: false,
  image_classified: true
};
let normalized_text;
if (caption) {
  normalized_text = caption;
} else if (j._skip_llm_calls) {
  normalized_text = '[descricao simulada]';
} else {
  normalized_text = '[descricao pendente v2]';
}
return {
  json: {
    phone: j.phone,
    msgId: j.msgId,
    messageType: j.messageType,
    normalized_text,
    media_summary: 'image',
    safety_flags: flags,
    should_handoff: false,
    handoff_reason: null,
    test_run_id: j.test_run_id
  }
};

const j = $json;
const filename = (j.media && j.media.filename) || '';
const text = j.text || '';
const haystack = (filename + ' ' + text);
const clinicalRegex = /exame|laudo|prescri[çc][aã]o|receita|CRM|diagn[oó]stico/i;
const isClinical = clinicalRegex.test(haystack);
const flags = {
  clinical: isClinical,
  sensitive_image: false,
  payment_proof: false,
  financial: false,
  unknown_media: false,
  audio_transcribed: false,
  image_classified: false
};
const normalized_text = text || filename || '[documento]';
return {
  json: {
    phone: j.phone,
    msgId: j.msgId,
    messageType: j.messageType,
    normalized_text,
    media_summary: filename || 'document',
    safety_flags: flags,
    should_handoff: isClinical,
    handoff_reason: isClinical ? 'documento_clinico_sensivel' : null,
    test_run_id: j.test_run_id
  }
};

const j = $json;
const flags = {
  clinical: false,
  sensitive_image: false,
  payment_proof: false,
  financial: false,
  unknown_media: true,
  audio_transcribed: false,
  image_classified: false
};
return {
  json: {
    phone: j.phone,
    msgId: j.msgId,
    messageType: j.messageType,
    normalized_text: j.text || '',
    media_summary: 'unknown',
    safety_flags: flags,
    should_handoff: true,
    handoff_reason: 'midia_desconhecida',
    test_run_id: j.test_run_id
  }
};
